problems = json.loads(problems_json)

# Group by file
files = {}
for p in problems:
    if p['path'] not in files:
        files[p['path']] = set()
    files[p['path']].add(p['startLine'])

for filepath, lines_to_ignore in files.items():
    if not os.path.exists(filepath):
        continue
    
    with open(filepath, "r", encoding="utf-8") as f:
        lines = f.readlines()
        
    for line_num in lines_to_ignore:
        idx = line_num - 1
        if 0 <= idx < len(lines):
            line = lines[idx]
            if '# type: ignore' not in line:
                line = line.rstrip() + "  # type: ignore\n"
                lines[idx] = line
                
    with open(filepath, "w", encoding="utf-8") as f:
        f.writelines(lines)
        
print("Applied type ignores to all problematic lines!")
